}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Blue Kachina REAPER Plugins\par}
{\pard \ql \f0 \sa180 \li0 \fi0 JSFX effects and utilities for Cockos REAPER.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Installation\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 1.\tx360\tab Install ReaPack.\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 2.\tx360\tab In REAPER, open: Extensions > ReaPack > Import repositories\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 3.\tx360\tab Add:\par}
{\pard \ql \f0 \sa180 \li360 \fi0 https://raw.githubusercontent.com/Blue-Kachina/reaper-plugins/main/index.xml\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 4.\tx360\tab Synchronize ReaPack.\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 5.\tx360\tab Browse and install the desired packages.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Packages\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Ultra8 \u8212- Multi-lane looper \u8212- A big expansion on the Super8 Looper that came with REAPER\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab MIDI Note Filter By Drum Type \u8212- Example: Can put it on a track to only let snare hits through\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab MIDI Echo - Like an audio-echo/delay, but in MIDI form. Allows subsequent echoes to change pitch/velocity\sa180\par}
}
